from flask import Flask, request, jsonify
import jwt
from functools import wraps

app = Flask(__name__)
SECRET_KEY = 'your_secret_key'

# Sample user database
users = {
    'user1': 'password1',
    'user2': 'password2'
}

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.args.get('token')  # Get the token from the query string

        if not token:
            return jsonify({'message': 'Token is missing!'}), 403

        try:
            data = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
            current_user = data['username']
        except:
            return jsonify({'message': 'Token is invalid!'}), 403

        return f(current_user, *args, **kwargs)

    return decorated

@app.route('/login')
def login():
    auth = request.authorization

    if auth and auth.password == users.get(auth.username):
        token = jwt.encode({'username': auth.username}, SECRET_KEY, algorithm="HS256")
        return jsonify({'token': token})

    return jsonify({'message': 'Could not verify!'}), 401

@app.route('/protected')
@token_required
def protected(current_user):
    return jsonify({'message': f'Hello {current_user}! This is a protected endpoint.'})

if __name__ == '__main__':
    app.run(debug=True)